mapper.select:
select date_format(create_time, '%Y-%m-%d') as dateStr, count(1) as count
from flight_application

    and applicant_id = #{applicantId}

        and date_format(create_time,'%Y-%m-%d') >= #{beginTime}


        and date_format(create_time,'%Y-%m-%d') <= #{endTime}


group by date_format(create_time, '%Y-%m-%d')
order by dateStr

select status as name, count(1) as value from flight_application
and applicant_id = #{applicantId}
group by status

select date_format(v.create_time, '%Y-%m-%d') as dateStr, count(1) as count
from violation_record v
join flight_permission p on v.permission_id = p.id
join flight_application a on p.application_id = a.id

    and a.applicant_id = #{applicantId}

        and date_format(v.create_time,'%Y-%m-%d') >= #{beginTime}


        and date_format(v.create_time,'%Y-%m-%d') <= #{endTime}


group by date_format(v.create_time, '%Y-%m-%d')
order by dateStr

select count(1) from flight_application
where date(create_time) = curdate()
and applicant_id = #{applicantId}

select count(1) from flight_application
where date(approve_time) = curdate() and status = '1'
and applicant_id = #{applicantId}
